import retrofit2.http.Path
import retrofit2.http.Query

interface UserApiService {

    @GET("users")
    suspend fun getUsers(
        @Query("page") page: Int = 1,
        @Query("per_page") perPage: Int = 20
    ): Response<PaginatedResponse<UserProfile>>

    @GET("users/{id}")
    suspend fun getUserById(
        @Path("id") userId: Long
    ): Response<ApiResponse<UserProfile>>

    @GET("users/me")
    suspend fun getCurrentUser(): Response<ApiResponse<UserProfile>>

    @PATCH("users/{id}")
    suspend fun updateUser(
        @Path("id") userId: Long,
        @Body updates: Map<String, Any>
    ): Response<ApiResponse<UserProfile>>

    @DELETE("users/{id}")
    suspend fun deleteUser(
        @Path("id") userId: Long
    ): Response<ApiResponse<Unit>>
}

// ============ NetworkResult.kt ============
package com.example.networking

sealed class NetworkResult<out T> {
    data class Success<T>(val data: T) : NetworkResult<T>()
    data class Error(val code: Int, val message: String) : NetworkResult<Nothing>()
    data class Exception(val throwable: Throwable) : NetworkResult<Nothing>()

    val isSuccess get() = this is Success
    val isError get() = this is Error
    val isException get() = this is Exception

    fun getOrNull(): T? = when (this) {
        is Success -> data
        else -> null
    }

    fun <R> map(transform: (T) -> R): NetworkResult<R> = when (this) {
        is Success -> Success(transform(data))
        is Error -> Error(code, message)
        is Exception -> Exception(throwable)
    }
}

// ============ NetworkModule.kt ============
package com.example.networking

import com.example.networking.api.UserApiService
import com.google.gson.GsonBuilder
import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

object NetworkModule {

    private var retrofit: Retrofit? = null
    private var okHttpClient: OkHttpClient? = null

    val tokenProvider: InMemoryTokenProvider = InMemoryTokenProvider()

    private const val CONNECT_TIMEOUT = 30L
    private const val READ_TIMEOUT = 30L
    private const val WRITE_TIMEOUT = 30L

    fun initialize(environment: Environment = Environment.DEV) {
        Environment.current = environment
        // Reset clients so they're rebuilt with new environment
        retrofit = null
        okHttpClient = null
    }

    private fun provideLoggingInterceptor(): HttpLoggingInterceptor {
        return HttpLoggingInterceptor().apply {
            level = when (Environment.current) {
                Environment.DEV -> HttpLoggingInterceptor.Level.BODY
                Environment.STAGING -> HttpLoggingInterceptor.Level.HEADERS
                Environment.PRODUCTION -> HttpLoggingInterceptor.Level.NONE
            }
        }
    }

    private fun provideOkHttpClient(): OkHttpClient {
        if (okHttpClient == null) {
            okHttpClient = OkHttpClient.Builder()
                .connectTimeout(CONNECT_TIMEOUT, TimeUnit.SECONDS)
                .readTimeout(READ_TIMEOUT, TimeUnit.SECONDS)
                .writeTimeout(WRITE_TIMEOUT, TimeUnit.SECONDS)
                .addInterceptor(AuthInterceptor(tokenProvider))
                .addInterceptor(provideLoggingInterceptor())
                .authenticator(TokenAuthenticator(tokenProvider))
                .build()
        }
        return okHttpClient!!
    }

    private fun provideRetrofit(): Retrofit {
        if (retrofit == null) {
            val gson = GsonBuilder()
                .setLenient()
                .create()

            retrofit = Retrofit.Builder()
                .baseUrl(Environment.current.baseUrl)
                .client(provideOkHttpClient())
                .addConverterFactory(GsonConverterFactory.create(gson))
                .build()
        }
        return retrofit!!
    }

    fun provideUserApiService(): UserApiService {
        return provideRetrofit().create(UserApiService::class.java)
    }

    inline fun <reified T> createService(): T {
        return provideRetrofit().create(T::class.java)
    }
}

// ============ SafeApiCall.kt ============
package com.example.networking

import retrofit2.Response

suspend fun <T> safeApiCall(apiCall: suspend () -> Response<T>): NetworkResult<T> {
    return try {
        val response = apiCall()
        if (response.isSuccessful) {
            val body = response.body()
            if (body != null) {
                NetworkResult.Success(body)
            } else {
                NetworkResult.Error(response.code(), "Response body is null")
            }
        } else {
            val errorBody = response.errorBody()?.string() ?: "Unknown error"
            NetworkResult.Error(response.code(), errorBody)
        }
    } catch (e: Exception) {
        NetworkResult.Exception(e)
    }
}

